/**
 * Calcula el IVA aplicado sobre el subtotal.
 * @param subtotal - El monto base sobre el cual se calcula el impuesto
 * @param tasa - La tasa de IVA en formato decimal (ejemplo: 0.12 para 12%)
 * @returns El monto correspondiente al IVA
 */
export function calcularIVA(subtotal, tasa) {
    return subtotal * tasa;
}
